import org.owasp.encoder.Encode;

import java.util.Scanner;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input using OWASP Java Encoder
        String sanitizedUserInput = Encode.forHtml(userInput);

        String greetingMessage = "Hello, " + sanitizedUserInput + "!";

        // Safe output with properly sanitized user input
        System.out.println("<html>");
        System.out.println("<body>");
        System.out.println("<h1>" + greetingMessage + "</h1>");
        System.out.println("</body>");
        System.out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
